import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./LoginPage.css";

const LoginPage: React.FC = () => {
    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");
    const navigate = useNavigate();

    const handleLogin = (e: React.FormEvent) => {
        e.preventDefault(); // Sayfa yenilenmesini önle

        // Varsayılan giriş kabul ediliyor
        if (username.trim() !== "" && password.trim() !== "") {
            localStorage.setItem("isAuthenticated", "true"); // Kullanıcı giriş yaptı olarak işaretleniyor
            navigate("/dashboard"); // Dashboard sayfasına yönlendir
        } else {
            alert("Please enter username and password!"); // Boş giriş engellendi
        }
    };

    return (
        <div className="login-container">
            <div className="login-box">
                <h2>Login</h2>
                <form onSubmit={handleLogin}>
                    <div className="input-group">
                        <label>Username</label>
                        <input
                            type="text"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            required
                        />
                    </div>
                    <div className="input-group">
                        <label>Password</label>
                        <input
                            type="password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                        />
                    </div>
                    <button type="submit">Login</button>
                </form>
                <div className="login-links">
                    <a href="#">Forgot my password?</a>
                    <a href="#" className="google-login">Login with Google</a>
                </div>
            </div>
        </div>
    );
};

export default LoginPage;
